checker_dsl:
EXISTS (`LoopStmt loop`, `Expr cond`) {
  AND {
    OR {
      EXISTS (`Expr loopReentry`, `ControlFlowNode last`) {
        AND {
          (`loop.getCondition() = cond`),
          OR {
            AND {
              (`loop instanceof ForStmt`),
              (`loop.(ForStmt).getAnUpdate()`),
              (`loopReentry = loop.(ForStmt).getUpdate(0)`)
            },
            AND {
              NOT { AND { (`loop instanceof ForStmt`), (`loop.(ForStmt).getAnUpdate()`) } },
              (`loopReentry = cond`)
            }
          },
          (`last.getEnclosingStmt().getEnclosingStmt*() = loop.getBody()`),
          (`last.getASuccessor().asExpr().getParent*() = loopReentry`)
        }
      },
      AND {
        OR {
          AND {
            (`loop instanceof ForStmt`),
            NOT { (`loop.getCondition()`) }
          },
          (`loop.getCondition().(BooleanLiteral).getBooleanValue() = true`)
        },
        EXISTS (`ConditionBlock cb`, `boolean branch`) {
          AND {
            (`cond = cb.getCondition()`),
            (`cond.getEnclosingStmt().getEnclosingStmt*() = loop.getBody()`),
            FORALL (`Stmt exit`) {
              OR {
                NOT {
                  OR {
                    AND {
                      (`exit.getEnclosingStmt*() = loop.getBody()`),
                      (`exit instanceof ReturnStmt`)
                    },
                    AND {
                      (`exit.getEnclosingStmt*() = loop.getBody()`),
                      (`exit instanceof BreakStmt`),
                      (`exit.(BreakStmt).getTarget() = loop.getEnclosingStmt*()`)
                    }
                  }
                },
                (`cb.controls(exit.getBasicBlock(), branch)`)
              }
            }
          }
        }
      }
    },
    FORALL (`SsaDefinition ssa`, `VarRead use`) {
      OR {
        NOT {
          AND {
            (`ssa.getARead() = use`),
            (`use.getParent*() = cond`)
          }
        },
        OR {
          NOT { (`ssa.getControlFlowNode().getEnclosingStmt().getEnclosingStmt*() = loop`) },
          (`ssa.getControlFlowNode().asExpr().getParent*() = loop.(ForStmt).getAnInit()`)
        }
      }
    },
    NOT { EXISTS (`MethodCall ma`) { (`ma.getParent*() = cond`) } },
    NOT { EXISTS (`FieldRead fa`) {
      AND {
        NOT { (`fa.getField().isFinal()`) },
        (`fa.getParent*() = cond`)
      }
    } },
    NOT { EXISTS (`ArrayAccess aa`) { (`aa.getParent*() = cond`) } }
  }
}
